/**
 * OPT Longevity
 * Page-specific styles for page-opt-longevity.php
 *
 * Desktop-first: base styles target desktop (1440px).
 * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
 * Mobile-only refinements via $small-screen-and-smaller (max-width: 600px).
 */
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;
@use '../variables/layout' as layout;

.opt-longevity {

	/*
	 * =============================
	 * Hero Section
	 * =============================
	 */
	.longevity-hero {
		background-color: colors.$color-white;
		border-top: 1px solid colors.$color-black-lightest;
		border-bottom: 1px solid colors.$color-black-lightest;
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 40px;
		padding: 40px 0 64px;

		@media #{layout.$medium-screen-and-smaller} {
			padding: 40px 0;
		}

		@media #{layout.$small-screen-and-smaller} {
			padding: 40px 0;
		}
	}

	/*
	 * Gallery — Faux 3D horizontal scroller
	 * Inspired by https://codepen.io/jh3y/pen/gOeXgXv
	 * Uses white pseudo-element ellipses at top/bottom to create a gentle
	 * curved barrel clip, matching the Figma's large ellipse overlays.
	 */
	.gallery-wrapper {
		--gallery-height: 225px;
		position: relative;
		width: 100%;
		overflow: hidden;

