* Testimonials
* =============================
*/
.testimonials {
	&::after {
		left: 50%;
	}
	.container {
		position: relative;
		padding: 4rem;
		@media #{layout.$medium-screen-and-smaller} {
			padding: 2.5rem 0;
		}
		@media #{layout.$small-screen-only} {
			padding: 2.5rem 0;
		}
		.wrapper {
			padding: 0;
		}
		.title-wrapper {
			max-width: 1000px;
			margin-inline: auto;
			text-align: center;
			margin-bottom: 2rem;
			padding-inline: 0;
			@media #{layout.$medium-screen-and-smaller} {
				padding-inline: 2.5rem;
			}
			@media #{layout.$small-screen-only} {
				padding-inline: 1rem;
			}
			h2 {
				color: #000;
				font-family: "STIX Two Text", serif;
				font-size: 3.625rem;
				font-weight: 400;
				line-height: 1;
				letter-spacing: -1.16px;
				margin-bottom: 1rem;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 2.25rem;
					letter-spacing: -0.72px;
				}
			}
			p {
				color: #000;
				font-family: "DM Sans", sans-serif;
				font-size: 1.375rem;
				font-weight: 500;
				line-height: 1;
				letter-spacing: -0.44px;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: 1.125rem;
					letter-spacing: -0.36px;
				}
			}
			.stars-wrapper {
				display: flex;
				flex-direction: row;
				align-items: center;
				justify-content: center;
				gap: fonts.rem(8px);
				margin-bottom: fonts.rem(16px);
				@media only screen and (max-width: 315px) {
					flex-direction: column;
				}
				img {
					width: fonts.rem(86px);
					height: fonts.rem(15px);
					position: relative;
					bottom: fonts.rem(1px);
				}
				span {
					color: colors.$color-black;
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(16px);
					font-weight: 400;
					line-height: 140%;
					letter-spacing: -0.16px;
				}
			}
		}
		.carousel-wrapper {		
			overflow-x: hidden;
			overflow-y: visible;
			width: 100%;
			max-width: 100vw;
			.slick-track {
				margin: auto;
				display: flex !important;
				align-items: stretch;
			}
			.testimonial-item {
				padding: 2rem;
				border-radius: 20px;
				background: #F1F0EF;
				flex-direction: column;
				gap: 1rem;
				margin-inline: 0.75rem;
				@media #{layout.$small-screen-only} {
					margin-inline: 0.25rem;
				}
				&-rating img {
					height: 15px;
					width: auto;
				}

				&-title span {
					color: #000;
					font-family: "DM Sans", sans-serif;
					font-size: 1.125rem;
					font-weight: 500;
					line-height: 1;
					letter-spacing: -0.36px;
					@media #{layout.$small-screen-only} {
						font-size: 1rem;
						font-weight: 700;
						letter-spacing: -0.32px;
					}
				}

				&-description {
					flex: 1;
					span {
						color: #000;
						font-family: "DM Sans", sans-serif;
						font-size: 1rem;
						font-weight: 400;
						line-height: 1.4;
						letter-spacing: -0.16px;
						@media #{layout.$small-screen-only} {
							font-size: 0.875rem;
							letter-spacing: -0.14px;
						}
					}
				}

				&-attribution {
					color: #000;
					font-family: "DM Sans", sans-serif;
					font-size: 1rem;
					font-weight: 400;
					line-height: 1.4;
					letter-spacing: -0.16px;
					span.name {
						font-weight: 700;
						line-height: 1;
						letter-spacing: -0.32px;
					}
				}

