@use '../variables/layout' as layout;

// Carousel navigation styles - matching slick carousel styles from overview light rebrand
.navigation-wrapper {
	align-items: center;
	justify-content: center;
	margin-top: 2rem;
	position: relative;
	height: 46px;
	display: flex;
	flex-direction: row;
	justify-content: center;
	align-items: center;
	gap: 1.5rem;

	@media #{layout.$medium-screen-and-smaller} {
		display: flex;
	}

	&.infographic-navigation {
		padding: 0 4rem;
		@media #{layout.$medium-screen-and-smaller} {
			padding: 0 2.5rem;
		}
		@media #{layout.$small-screen-only} {
			padding: 0 1.5rem;
		}
	}

	.previous,
	.next {
		width: 46px;
		height: 46px;
		z-index: 1;
		top: 0;
		transform: none;

		button {
			background: none;
			border: none;
			cursor: pointer;
			padding: 0;
			width: 100%;
			height: 100%;
			display: flex;
			align-items: center;
			justify-content: center;
			transition: opacity 0.3s ease;

			&:hover {
				opacity: 0.8;
			}

			&:before {
				content: "";
				background-size: contain;
				background-repeat: no-repeat;
				width: 46px;
				height: 46px;
				display: block;
			}

			img {
				display: none; // Hide original img since we're using :before pseudo-element
			}
		}
	}

	.previous {
		button:before {
			background-image: url("../media/images/icons/arrow-circle_left.svg");
		}
	}

	.next {
		button:before {
			background-image: url("../media/images/icons/arrow-circle_right.svg");
		}
	}

	.nav-dots {
		display: flex;
		justify-content: center;
		align-items: center;
		gap: 8px;
		position: relative;
		width: auto;
		height: 46px;

		.nav-dot {
			background-color: rgba(96, 91, 82, 0.6);
			border: none;
			width: 12px;
			height: 12px;
			border-radius: 100%;
			cursor: pointer;
			transition: all 0.3s ease;
			max-width: none;
			max-height: none;

			&:hover {
				opacity: 0.8;
			}

			&.active {
				background-color: #fff;
				border: 1px solid #0E0B20;
				padding: 0.5px;
				position: relative;
				width: 16px;
				height: 16px;
				transform: none;

				&:before {
					content: "";
					display: block;
					width: calc(100% - 1px);
					height: calc(100% - 1px);
					background-color: #0E0B20;
					border-radius: 100%;
					margin: 0.5px;
				}
			}
		}
	}
}

