	.care-callout {
		background-color: colors.$color-white;

		.container {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(64px);
			padding: fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(48px);
				padding: fonts.rem(48px) fonts.rem(24px);
			}
		}

		// ——— Tout block ———
		.tout-block {
			display: grid;
			grid-template-columns: 1fr 1fr;
			gap: fonts.rem(64px);
			align-items: center;

			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(32px);
			}
		}

		.tout-content {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(20px);
			}
		}

		.title {
			font-family: fonts.$STIX-Two-Text;
			font-weight: 400;
			font-size: fonts.rem(42px);
			line-height: 1;
			letter-spacing: -0.84px;
			color: colors.$color-black;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(29px);
				letter-spacing: -0.58px;
			}
		}

		.stars-wrapper {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			img {
				width: fonts.rem(90px);
				height: auto;
			}

			span {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				line-height: 1.4;
				color: colors.$color-black;
			}
		}

		.featured-review {
			margin: 0;
			padding: 0;
			display: flex;
			flex-direction: column;
			gap: fonts.rem(12px);

			p {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(18px);
				font-weight: 400;
				line-height: 1.5;
				letter-spacing: -0.18px;
				color: colors.$color-black;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(16px);
				}
			}

			footer {
				display: flex;
				flex-direction: row;
				align-items: center;
				gap: fonts.rem(8px);

				.name {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 700;
					color: colors.$color-black;
				}

				.label {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 400;
					color: rgba(96, 91, 82, 0.6);

					&::before {
						content: '·';
						margin-right: fonts.rem(8px);
					}
				}
			}
		}

		.cta-button {
			display: flex;
			align-items: center;
			justify-content: center;
			height: fonts.rem(48px);
			padding: 0 fonts.rem(32px);
			background-color: colors.$color-yellow;
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 500;
			letter-spacing: -0.16px;
			border-radius: 2px;
			text-decoration: none;
			transition: background-color 0.2s ease;
			align-self: flex-start;

			&:hover {
				background-color: colors.$color-yellow-dark;
			}

			@media #{layout.$medium-screen-and-smaller} {
				width: 100%;
				align-self: stretch;
			}
		}

		// ——— Doctor grid ———
		.doctor-grid {
			display: grid;
			grid-template-columns: repeat(2, 1fr);
			gap: fonts.rem(12px);

			@media #{layout.$medium-screen-and-smaller} {
				// 4 tiles in a single scrollable row on mobile
				grid-template-columns: repeat(4, 1fr);
				gap: fonts.rem(8px);
			}
		}

		.doctor-tile {
			border-radius: fonts.rem(20px);
			overflow: hidden;
			aspect-ratio: 244 / 282;

			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
			}
		}

		// ——— Carousel block ———
		.carousel-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(32px);
		}

		.care-callout-carousel {
			overflow-x: hidden;
			overflow-y: visible;
			width: 100%;

			// Slick core inline
			.slick-list {
				overflow: hidden;
				display: block;
				margin: 0;
				padding: 0;

				&.dragging img { pointer-events: none; }
			}

			.slick-track {
				display: flex !important;
				align-items: stretch;
				margin: auto;
			}

			.slick-slide {
				height: inherit;

				> div {
					height: 100%;
				}
			}

			.slick-initialized .review-card {
				display: flex !important;
			}
		}

		.review-card {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(16px);
			padding: fonts.rem(24px);
			background-color: #f1f0ef;
			border-radius: fonts.rem(20px);
			margin-inline: fonts.rem(8px);
			height: 100%;

			@media #{layout.$medium-screen-and-smaller} {
				margin-inline: fonts.rem(6px);
			}
		}

		.review-rating img {
			height: fonts.rem(16px);
			width: auto;
		}

		.review-title {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(18px);
			font-weight: 700;
			line-height: 1;
			letter-spacing: -0.36px;
			color: colors.$color-black;
			margin: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(16px);
			}
		}

		.review-text {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 400;
			line-height: 1.5;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;
			flex: 1;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(14px);
			}
		}

		.review-attribution {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			.name {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 700;
				color: colors.$color-black;
			}

			.label {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				color: rgba(96, 91, 82, 0.6);

				&::before {
					content: '·';
					margin-right: fonts.rem(8px);
				}
			}
		}

		// ——— Navigation ———
		.care-callout-navigation {
			margin-top: 0;
		}
	}
}

