}

() => {
  // Check if cards are actually being painted - look at the actual pixel content area
  const list = document.querySelector('.care-callout-carousel .slick-list');
  const rect = list.getBoundingClientRect();

  // Also check if there's a z-index or clip issue
  const carousel = document.querySelector('.care-callout-carousel');
  const cs = getComputedStyle(carousel);

  // Check parent chain for overflow issues
  let el = carousel;
  const chain = [];
  while (el && el !== document.body) {
    const style = getComputedStyle(el);
    if (style.overflow !== 'visible' || style.overflowX !== 'visible' || style.overflowY !== 'visible') {
      chain.push({ tag: el.className, overflow: style.overflow, overflowX: style.overflowX, overflowY: style.overflowY });
    }
    el = el.parentElement;
  }

  return {
    listRect: rect,
    carouselOverflow: cs.overflow,
    carouselOverflowX: cs.overflowX,
    carouselOverflowY: cs.overflowY,
    overflowChain: chain,
  };
}

() => {
  // Get the active slide and its position
  const activeSlide = document.querySelector('.care-callout-carousel .slick-active');
  if (!activeSlide) return { error: 'no active slide' };

  const rect = activeSlide.getBoundingClientRect();
  const card = activeSlide.querySelector('.review-card');
  const cardRect = card?.getBoundingClientRect();
  const cardBg = card ? getComputedStyle(card).backgroundColor : null;

  return {
    activeSlideRect: rect,
    cardRect,
    cardBg,
    activeSlideIndex: activeSlide.dataset.slickIndex,
    inViewport: rect.top >= 0 && rect.top < window.innerHeight,
  };
}

() => {
  // Find which slides are actually visible in viewport
  const slides = document.querySelectorAll('.care-callout-carousel .slick-slide');
  const visible = [];
  slides.forEach(slide => {
    const rect = slide.getBoundingClientRect();
    if (rect.right > 64 && rect.left < 1376) {
      const card = slide.querySelector('.review-card');
      visible.push({
        index: slide.dataset.slickIndex,
        rect: { x: Math.round(rect.x), width: Math.round(rect.width), height: Math.round(rect.height) },
        isClone: slide.classList.contains('slick-cloned'),
        cardExists: !!card,
        cardBg: card ? getComputedStyle(card).backgroundColor : 'NO CARD',
      });
    }
  });
  return visible;
}

() => {
  const slides = document.querySelectorAll('.care-callout-carousel .slick-slide');
  return Array.from(slides).map(slide => {
    const rect = slide.getBoundingClientRect();
    return {
      index: slide.dataset.slickIndex,
      x: Math.round(rect.x),
      width: Math.round(rect.width),
      height: Math.round(rect.height),
    };
  });
}

() => {
  // Check inline styles on slides 2-5
  const slides = document.querySelectorAll('.care-callout-carousel .slick-slide');
  return Array.from(slides).slice(0, 8).map(slide => ({
    index: slide.dataset.slickIndex,
    inlineStyle: slide.getAttribute('style'),
    display: getComputedStyle(slide).display,
    ariaHidden: slide.getAttribute('aria-hidden'),
  }));
}

() => {
  // Find which CSS rule is applying display:none to aria-hidden elements
  const slide = document.querySelector('.care-callout-carousel .slick-slide[aria-hidden="true"]');
  if (!slide) return 'no hidden slide';

  const sheets = Array.from(document.styleSheets);
  const matches = [];
  for (const sheet of sheets) {
    try {
      const rules = Array.from(sheet.cssRules || []);
      for (const rule of rules) {
        if (rule.selectorText && rule.selectorText.includes('aria-hidden')) {
          matches.push({ selector: rule.selectorText, cssText: rule.cssText.slice(0, 200), href: sheet.href });
        }
      }
    } catch(e) {}
  }
  return matches;
}

