			align-items: center;
			justify-content: center;
			gap: fonts.rem(24px);

			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
			}
		}

		.nav-arrow {
			background: none;
			border: none;
			padding: 0;
			cursor: pointer;
			flex-shrink: 0;
			line-height: 0;

