			margin-bottom: fonts.rem(24px);

			@media #{layout.$small-screen-and-smaller} {
				padding: 0 fonts.rem(16px);
			}

			.biomarker-card {
				width: 100%;
				max-width: fonts.rem(330px);
				height: fonts.rem(229px);

				.zone-labels .zone-label {
					font-size: fonts.rem(12px);
					letter-spacing: 0.01em;
				}

				.data-marker {
					&.in-range-marker { right: 12%; top: 20%; }
					&.out-of-range-marker { left: 10%; top: 50%; }
				}

				.marker-dot {
					width: fonts.rem(17px);
					height: fonts.rem(17px);
				}
			}
		}

		// The biomarker data card
		.biomarker-card {
			position: relative;
			width: fonts.rem(243px);
			height: fonts.rem(168px);
			background: white;
			border: 1px solid rgba(210, 206, 196, 0.6);
			border-radius: fonts.rem(8.4px);
			overflow: hidden;

			// Left: "In Range" / "Out of Range" labels
			.zone-labels {
				position: absolute;
				left: 0;
				top: 0;
				width: 28%;
				height: 100%;
				display: flex;
				flex-direction: column;

				.zone-label {
					flex: 1;
					display: flex;
					align-items: center;
					justify-content: center;
					font-family: 'Azeret Mono', monospace;
					font-size: fonts.rem(9px);
					line-height: 1.2;
					text-align: center;
					color: rgba(96, 91, 82, 0.8);
					letter-spacing: 0.01em;
				}
			}

			// Thin vertical color bars indicating zone
			.range-bar-col {
				position: absolute;
				left: 28%;
				top: fonts.rem(15px);
				bottom: fonts.rem(15px);
				width: fonts.rem(8px);
				display: flex;
				flex-direction: column;

				.range-bar {
					&.green-zone {
						flex: 0 0 47%;
						background-color: #ccffee;
					}
					&.pink-zone {
						flex: 1;
						background-color: #ffe0e1;
					}
				}
			}

			// Chart area: dashed lines, trend path, data point markers
			.chart-area {
				position: absolute;
				left: calc(28% + #{fonts.rem(8px)});
				top: 0;
				right: 0;
				bottom: 0;

				.chart-line {
					position: absolute;
					left: 0;
					right: 0;
					height: 1px;
					background-image: repeating-linear-gradient(
						to right,
						rgba(96, 91, 82, 0.25) 0,
						rgba(96, 91, 82, 0.25) 4px,
						transparent 4px,
						transparent 8px
					);

					&.top-line    { top: fonts.rem(15px); }
					&.mid-line    { top: 47%; }
					&.bottom-line { bottom: fonts.rem(15px); }
				}

				.trend-svg {
					position: absolute;
					inset: 0;
					width: 100%;
					height: 100%;
					pointer-events: none;
				}

				.data-marker {
					position: absolute;
					display: flex;
					flex-direction: column;
					align-items: center;

					// Out-of-range: lower-left
					&.out-of-range-marker {
						left: 8%;
						top: 52%;
					}

					// In-range: upper-right
					&.in-range-marker {
						right: 10%;
						top: 19%;
					}
				}

				.marker-dot {
					width: fonts.rem(13px);
					height: fonts.rem(13px);
					border-radius: 50%;
					border: 2px solid white;
					box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
					flex-shrink: 0;

					&.green-dot { background-color: #20c475; }
					&.red-dot   { background-color: #fc5358; }
				}

				.marker-stem {
					width: 1px;
					height: fonts.rem(28px);
					background: linear-gradient(to bottom, rgba(210, 206, 196, 0.5), transparent);
					margin-top: 2px;
				}
			}
		}
	}

	/*
	 * =============================
	 * Care Callout
	 * =============================
	 */
	.care-callout {
		background-color: colors.$color-white;

		.container {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(64px);
			padding: fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(48px);
				padding: fonts.rem(48px) fonts.rem(24px);
			}
		}

		// ——— Tout block ———
		.tout-block {
			display: grid;
			grid-template-columns: 1fr 1fr;
			gap: fonts.rem(64px);
			align-items: center;

			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(32px);
			}
		}

		.tout-content {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(20px);
			}
		}

		.title {
			font-family: fonts.$STIX-Two-Text;
			font-weight: 400;
			font-size: fonts.rem(42px);
			line-height: 1;
			letter-spacing: -0.84px;
			color: colors.$color-black;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(29px);
				letter-spacing: -0.58px;
			}
		}

		.stars-wrapper {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			img {
				width: fonts.rem(90px);
				height: auto;
			}

			span {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				line-height: 1.4;
				color: colors.$color-black;
			}
		}

		.featured-review {
			margin: 0;
			padding: 0;
			display: flex;
			flex-direction: column;
			gap: fonts.rem(12px);

			p {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(18px);
				font-weight: 400;
				line-height: 1.5;
				letter-spacing: -0.18px;
				color: colors.$color-black;
				margin: 0;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(16px);
				}
			}

			footer {
				display: flex;
				flex-direction: row;
				align-items: center;
				gap: fonts.rem(8px);

				.name {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 700;
					color: colors.$color-black;
				}

				.label {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 400;
					color: rgba(96, 91, 82, 0.6);

					&::before {
						content: '·';
						margin-right: fonts.rem(8px);
					}
				}
			}
		}

		.cta-button {
			display: flex;
			align-items: center;
			justify-content: center;
			height: fonts.rem(48px);
			padding: 0 fonts.rem(32px);
			background-color: colors.$color-yellow;
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 500;
			letter-spacing: -0.16px;
			border-radius: 2px;
			text-decoration: none;
			transition: background-color 0.2s ease;
			align-self: flex-start;

			&:hover {
				background-color: colors.$color-yellow-dark;
			}

			@media #{layout.$medium-screen-and-smaller} {
				width: 100%;
				align-self: stretch;
			}
		}

		// ——— Doctor grid ———
		.doctor-grid {
			display: grid;
			grid-template-columns: repeat(2, 1fr);
			gap: fonts.rem(12px);

			@media #{layout.$medium-screen-and-smaller} {
				// 4 tiles in a single row strip on mobile
				grid-template-columns: repeat(4, 1fr);
				gap: fonts.rem(8px);
			}
		}

		.doctor-tile {
			border-radius: fonts.rem(20px);
			overflow: hidden;
			aspect-ratio: 244 / 282;

			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
			}
		}

		// ——— Carousel block ———
		.carousel-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(32px);
		}

		.care-callout-carousel {
			overflow-x: hidden;
			overflow-y: visible;
			width: 100%;

			// Slick core inline
			.slick-list {
				overflow: hidden;
				display: block;
				margin: 0;
				padding: 0;

				&.dragging img { pointer-events: none; }
			}

			.slick-track {
				display: flex !important;
				align-items: stretch;
				margin: auto;
			}

			.slick-slide {
				height: inherit;

				> div { height: 100%; }
			}

			.slick-initialized .review-card {
				display: flex !important;
			}
		}

		.review-card {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(16px);
			padding: fonts.rem(24px);
			background-color: #f1f0ef;
			border-radius: fonts.rem(20px);
			margin-inline: fonts.rem(8px);
			height: 100%;

			@media #{layout.$medium-screen-and-smaller} {
				margin-inline: fonts.rem(6px);
			}
		}

		.review-rating img {
			height: fonts.rem(16px);
			width: auto;
		}

		.review-title {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(18px);
			font-weight: 700;
			line-height: 1;
			letter-spacing: -0.36px;
			color: colors.$color-black;
			margin: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(16px);
			}
		}

		.review-text {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 400;
			line-height: 1.5;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;
			flex: 1;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(14px);
			}
		}

		.review-attribution {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			.name {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 700;
				color: colors.$color-black;
			}

			.label {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				color: rgba(96, 91, 82, 0.6);

				&::before {
					content: '·';
					margin-right: fonts.rem(8px);
				}
			}
		}

		// ——— Navigation ———
		.care-callout-navigation {
			margin-top: 0;
		}
	}
}

@keyframes marquee-scroll {
	from {
		transform: translateX(0);
	}
	to {
		transform: translateX(var(--marquee-offset, -50%));
	}
}

