		.review-text {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 400;
			line-height: 1.5;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;
			flex: 1;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(14px);
			}
		}

		.review-attribution {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			.name {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 700;
				color: colors.$color-black;
