/**
 * OPT Longevity
 * Page-specific styles for page-opt-longevity.php
 *
 * Desktop-first: base styles target desktop (1440px).
 * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
 * Mobile-only refinements via $small-screen-and-smaller (max-width: 600px).
 */
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;
@use '../variables/layout' as layout;

.opt-longevity {

	/*
	 * =============================
	 * Hero Section
	 * =============================
	 */
	.longevity-hero {
		background-color: colors.$color-white;
		border-top: 1px solid colors.$color-black-lightest;
		border-bottom: 1px solid colors.$color-black-lightest;
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 40px;
		padding: 40px 0 64px;

		@media #{layout.$medium-screen-and-smaller} {
			padding: 40px 0;
		}

		@media #{layout.$small-screen-and-smaller} {
			padding: 40px 0;
		}
	}

	/*
	 * Gallery — Faux 3D horizontal scroller
	 * Inspired by https://codepen.io/jh3y/pen/gOeXgXv
	 * Uses white pseudo-element ellipses at top/bottom to create a gentle
	 * curved barrel clip, matching the Figma's large ellipse overlays.
	 */
	.gallery-wrapper {
		--gallery-height: 225px;
		position: relative;
		width: 100%;
		overflow: hidden;

		// Top and bottom curved clips — white ellipses that overlay the gallery edges
		&::before,
		&::after {
			content: '';
			position: absolute;
			left: -10%;
			width: 120%;
			height: 80px;
			z-index: 1;
			pointer-events: none;
			background: colors.$color-white;
			border-radius: 50%;
		}

		&::before {
			top: -60px;
		}

		&::after {
			bottom: -60px;
		}

		@media #{layout.$medium-screen-and-smaller} {
			--gallery-height: 180px;

			&::before,
			&::after {
				height: 60px;
			}

			&::before {
				top: -44px;
			}

			&::after {
				bottom: -44px;
			}
		}

		@media #{layout.$small-screen-and-smaller} {
			--gallery-height: 126px;

			&::before,
			&::after {
				height: 50px;
			}

			&::before {
				top: -36px;
			}

			&::after {
				bottom: -36px;
			}
		}
	}

	.gallery-scroller {
		display: flex;
		gap: 32px;
		height: var(--gallery-height);
		overflow-x: auto;
		overflow-y: hidden;
		scrollbar-width: none;
		scroll-snap-type: x proximity;

		&::-webkit-scrollbar {
			display: none;
		}

		@media #{layout.$medium-screen-and-smaller} {
			gap: 24px;
		}

		@media #{layout.$small-screen-and-smaller} {
			gap: 18px;
		}
	}

	.gallery-item {
		flex-shrink: 0;
		height: 100%;
		scroll-snap-align: center;

		img {
			height: 100%;
			width: auto;
			object-fit: cover;
			display: block;
		}
	}

	/*
	 * Content — Text, CTA, badges
	 */
	.content-wrapper {
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 24px;
		max-width: 900px;
		width: 100%;
		padding: 0 64px;
		text-align: center;

		@media #{layout.$medium-screen-and-smaller} {
			padding: 0 32px;
		}

		@media #{layout.$small-screen-and-smaller} {
			padding: 0 16px;
		}
	}

	.title-block {
		display: flex;
		flex-direction: column;
		align-items: center;
	}

	.title {
		font-family: fonts.$STIX-Two-Text;
		font-weight: 400;
		font-size: 54px;
		line-height: 1;
		letter-spacing: -1.08px;
		color: colors.$color-black;
		max-width: 576px;
		margin: 0;

		@media #{layout.$medium-screen-and-smaller} {
			font-size: 36px;
			letter-spacing: -0.72px;
			max-width: 100%;
		}
	}

	.content-block {
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 20px;
		width: 100%;
	}

	.subtitle {
		font-family: fonts.$DM-Sans;
		font-weight: 500;
		font-size: 22px;
		line-height: 1.1;
		letter-spacing: -0.44px;
		color: colors.$color-black;
		margin: 0;

		@media #{layout.$medium-screen-and-smaller} {
			font-size: 18px;
			letter-spacing: -0.36px;
		}
	}

	.price-line {
		font-family: fonts.$DM-Sans;
		font-weight: 500;
		font-size: 22px;
		line-height: 1.1;
		letter-spacing: -0.44px;
		color: colors.$color-black;
		margin: 0;

		@media #{layout.$medium-screen-and-smaller} {
			font-size: 18px;
			letter-spacing: -0.36px;
		}
	}

	.cta-block {
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 8px;
		width: 100%;
	}

	.cta-button {
