			padding: fonts.rem(60px) fonts.rem(60px);

			@media #{layout.$medium-screen-and-smaller} {
				padding: fonts.rem(40px) 0;
				gap: fonts.rem(24px);
			}
		}

		.title-block {
			text-align: center;
			width: 100%;

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(65px);
				line-height: 0.95;
				letter-spacing: 0;
				color: colors.$color-black;
				margin: 0;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(38px);
					padding: 0 fonts.rem(16px);
				}
			}
		}

		.carousel-wrapper {
			width: 100%;
		}

		// Slick core layout rules
		.how-it-works-carousel {
			.slick-list {
				position: relative;
				overflow: hidden;
				margin: 0 -12px;
			}

			.slick-track {
				position: relative;
			}

			.slick-slide {
				float: left;
				min-height: 1px;
				display: none;
				padding: 0 12px;
			}

			&.slick-initialized .slick-slide {
				display: block;
			}
		}

		.step-card {
			// transparent slide container — visual styles live on .step-card-inner
		}

		.step-card-inner {
			background-color: #f1f0ef;
			border-radius: 20px;
			overflow: hidden;
		}

		.card-image {
			width: 100%;
			aspect-ratio: 322 / 261;
			overflow: hidden;

			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
			}
		}

		.card-content {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(8px);
			padding: fonts.rem(16px) fonts.rem(16px) fonts.rem(24px);
			flex: 1;
		}

		.card-heading {
			font-family: fonts.$DM-Sans;
			font-weight: 500;
			font-size: fonts.rem(22px);
			line-height: 1.1;
			letter-spacing: -0.44px;
			color: colors.$color-black;
			margin: 0;
		}

		.card-description {
			font-family: fonts.$DM-Sans;
			font-weight: 400;
			font-size: fonts.rem(16px);
			line-height: 1.4;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;
		}

		.carousel-nav {
			display: none;
			align-items: center;
			justify-content: center;
			gap: fonts.rem(24px);

			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
			}
		}

		.nav-arrow {
			background: none;
			border: none;
			padding: 0;
			cursor: pointer;
			flex-shrink: 0;
			line-height: 0;

			img {
				width: 48px;
				height: 48px;
				display: block;
			}

			&:hover img {
				opacity: 0.8;
			}
		}

		.how-it-works-dots {
			display: flex;
			align-items: center;
			justify-content: center;
			min-width: fonts.rem(84px);

			.slick-dots {
				list-style: none;
				padding: 0;
				margin: 0;
				display: flex !important;
				align-items: center;
				gap: fonts.rem(8px);
				position: static;
				bottom: auto;

				li {
					margin: 0;
					width: auto;
					height: auto;
					line-height: 0;

					button {
						width: 12px;
						height: 12px;
						border-radius: 50%;
						background-color: rgba(96, 91, 82, 0.3);
						border: none;
						padding: 0;
						cursor: pointer;
						font-size: 0;
						line-height: 0;
						transition: background-color 0.3s ease;

						&::before {
							display: none;
						}
					}

					&.slick-active button {
						background-color: colors.$color-black;
					}
				}
			}
		}

		.cta-block {
			width: fonts.rem(366px);

			@media #{layout.$medium-screen-and-smaller} {
				width: calc(100% - fonts.rem(32px));
			}
		}

		.cta-button {
			display: flex;
			align-items: center;
			justify-content: center;
			background-color: colors.$color-yellow;
			border: 1px solid colors.$color-gray-medium-transparent;
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-weight: 500;
			font-size: fonts.rem(16px);
			line-height: 1.3;
			letter-spacing: -0.32px;
			height: fonts.rem(48px);
			padding: 0 fonts.rem(48px);
			border-radius: 2px;
			text-decoration: none;
			cursor: pointer;
			width: 100%;

			&:hover {
				background-color: colors.$color-yellow-dark;
			}
		}
	}

	/*
	 * =============================
	 * Buy Box Section
	 * =============================
	 */
	.buy-box {
		background-color: colors.$color-white;

		.container {
			display: grid;
			grid-template-columns: 1fr 1fr;
			gap: fonts.rem(64px);
			align-items: start;
			padding: fonts.rem(40px) fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(24px);
				padding: fonts.rem(40px) 0;
			}
		}

		// Left — image gallery
		.gallery-wrapper {
			.image-grid {
				display: grid;
				grid-template-columns: repeat(2, 1fr);
				gap: fonts.rem(8px);

				.grid-tile {
					aspect-ratio: 1 / 1;
					overflow: hidden;
					border-radius: fonts.rem(8px);
					background-color: #f1f0ef;

					img {
						width: 100%;
						height: 100%;
						object-fit: cover;
						display: block;
					}
				}
			}

			// Mobile carousel + thumbs
			.buy-box-slider-wrapper {
				overflow: hidden;
				min-width: 0;

				.buy-box-main-carousel {
					position: relative;
					display: flex;
					overflow-x: auto;
					scroll-snap-type: x mandatory;
					-webkit-overflow-scrolling: touch;
					scrollbar-width: none;
					gap: fonts.rem(8px);
					margin-bottom: fonts.rem(12px);
					cursor: grab;
					padding-left: fonts.rem(32px);
					scroll-padding-left: fonts.rem(32px);

					@media #{layout.$small-screen-and-smaller} {
						padding-left: fonts.rem(16px);
						scroll-padding-left: fonts.rem(16px);
					}

					&::-webkit-scrollbar {
						display: none;
					}

					&::after {
						content: '';
						flex-shrink: 0;
						width: fonts.rem(32px);
						order: 9999;
					}

					.slide {
						scroll-snap-align: start;
						flex-shrink: 0;
						width: calc(100% - #{fonts.rem(32px)});
						max-width: fonts.rem(462px);

						@media #{layout.$small-screen-and-smaller} {
							width: calc(100% - #{fonts.rem(16px)});
						}

						img {
							width: 100%;
							aspect-ratio: 1 / 1;
							object-fit: cover;
							display: block;
							border-radius: fonts.rem(8px);
						}
					}
				}

				.buy-box-thumbs {
					display: flex;
					gap: fonts.rem(8px);
					padding: 0 fonts.rem(32px);

					@media #{layout.$small-screen-and-smaller} {
						padding: 0 fonts.rem(16px);
					}

					.thumb {
						flex: 1 1 0;
						min-width: 0;
						cursor: pointer;

						img {
							width: 100%;
							aspect-ratio: 1 / 1;
							object-fit: cover;
							display: block;
							border-radius: fonts.rem(4px);
							border: 2px solid transparent;
							opacity: 0.5;
							transition: opacity 0.2s ease, border-color 0.2s ease;
						}

						&.active img {
							opacity: 1;
							border-color: colors.$color-black;
						}
					}
				}
			}
		}

		// Right — content + FAQs
		.content-wrapper {
			display: flex;
			flex-direction: column;
			gap: 0;

			@media #{layout.$medium-screen-and-smaller} {
				padding-inline: fonts.rem(32px);
			}

			@media #{layout.$small-screen-and-smaller} {
				padding-inline: fonts.rem(16px);
			}
		}

		.content-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);

			.title-block {
				display: flex;
				align-items: baseline;
				justify-content: space-between;
				gap: fonts.rem(16px);

				.title {
					font-family: fonts.$STIX-Two-Text;
					font-weight: 400;
					font-size: fonts.rem(54px);
					line-height: 1;
					letter-spacing: -1.08px;
					color: colors.$color-black;

					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(36px);
						letter-spacing: -0.72px;
					}
				}

				.price {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(32px);
					line-height: 1.1;
					letter-spacing: -0.64px;
					color: colors.$color-black;
					white-space: nowrap;
					flex-shrink: 0;

					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(28px);
						letter-spacing: -0.56px;
					}
				}
			}

			.description {
				font-family: fonts.$DM-Sans;
				font-weight: 500;
				font-size: fonts.rem(22px);
				line-height: 1.1;
				letter-spacing: -0.44px;
				color: colors.$color-black;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(18px);
					letter-spacing: -0.36px;
				}
			}

			.feature-list {
				list-style: none;
				padding: 0;
				margin: 0;
				display: flex;
				flex-direction: column;
				gap: fonts.rem(16px);

				@media #{layout.$medium-screen-and-smaller} {
					gap: fonts.rem(12px);
				}

				li {
					border-left: 2px solid rgba(96, 91, 82, 0.2);
					padding-left: fonts.rem(12px);
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(22px);
					line-height: 1.1;
					letter-spacing: -0.44px;
					color: colors.$color-black;

					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(18px);
						letter-spacing: -0.36px;
						padding-left: fonts.rem(8px);
					}
				}
			}

			.cta-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);

				.cta-button {
					display: flex;
					align-items: center;
					justify-content: center;
					width: 100%;
					height: fonts.rem(48px);
					background-color: colors.$color-yellow;
					border: 1px solid rgba(14, 11, 32, 0.2);
					border-radius: 2px;
					padding: 0 fonts.rem(48px);
					color: colors.$color-black;
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(16px);
					line-height: 1.3;
					letter-spacing: -0.32px;
					text-decoration: none;
					cursor: pointer;
					box-sizing: border-box;

					&:hover {
						background-color: colors.$color-yellow-dark;
					}
				}

				.badges-wrapper {
					display: flex;
					flex-wrap: wrap;
					align-items: center;
					justify-content: center;
					gap: fonts.rem(10px);

					.badge {
						display: flex;
						align-items: center;
						gap: fonts.rem(4px);
						height: 20px;

						img {
							width: auto;
							height: 24px;
						}

						span {
							font-family: fonts.$DM-Sans;
							font-weight: 400;
							font-size: fonts.rem(14px);
							line-height: 1.4;
							letter-spacing: -0.28px;
							color: colors.$color-gray;
						}
					}
				}
			}
		}

		// FAQ accordion
		.faq-block {
			margin-top: fonts.rem(40px);

			.faq-item {
				border-bottom: 1px solid rgba(96, 91, 82, 0.2);

				&:first-child {
					border-top: 1px solid rgba(96, 91, 82, 0.2);
				}
			}

			.faq-header {
				display: flex;
				align-items: center;
				justify-content: space-between;
				padding: fonts.rem(12px) 0;
				cursor: pointer;
				gap: fonts.rem(16px);

				.faq-question {
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(18px);
					line-height: 1.1;
					letter-spacing: -0.36px;
					color: #202020;
				}

				.faq-icon {
					display: flex;
					align-items: center;
					justify-content: center;
					width: 24px;
					height: 24px;
					flex-shrink: 0;
					position: relative;

					.icon-line {
						position: absolute;
						background-color: colors.$color-black;
						transition: transform 0.3s ease;
					}

					.line-horizontal {
						width: 24px;
						height: 1px;
					}

					.line-vertical {
						width: 1px;
						height: 24px;
					}
				}
			}

			.faq-content {
				max-height: 0;
				overflow: hidden;
				transition: max-height 0.4s ease;

				.faq-item-answer {
					padding: 0 0 fonts.rem(16px);
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.4;
					letter-spacing: -0.14px;
					color: colors.$color-black;
				}
			}

			.faq-item.active {
				.faq-icon .line-vertical {
					transform: rotate(90deg);
				}

				.faq-content {
					max-height: 500px;
				}
			}
		}
	}

	/*
	 * =============================
	 * Disease Monitor Section
	 * =============================
	 */
	.disease-monitor {
		background-color: colors.$color-white;
		padding: fonts.rem(64px);

		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(40px) fonts.rem(32px);
		}

		@media #{layout.$small-screen-and-smaller} {
			padding: fonts.rem(32px) fonts.rem(16px);
		}

		// Rounded inner card (clips the wide parallax rows)
		.section-inner {
			background: rgba(241, 240, 239, 0.85);
			border-radius: fonts.rem(20px);
			overflow: hidden;
			padding: fonts.rem(64px) 0;
			box-shadow:
				0px 82px 33px rgba(0, 0, 0, 0.01),
				0px 46px 28px rgba(0, 0, 0, 0.03),
				0px 20px 20px rgba(0, 0, 0, 0.05),
				0px 5px 11px rgba(0, 0, 0, 0.06);

			@media #{layout.$medium-screen-and-smaller} {
				padding: fonts.rem(32px) 0;
			}
		}

		// Title + badges
		.title-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(8px);
			align-items: center;
			text-align: center;
			padding-inline: fonts.rem(64px);
			margin-bottom: fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				padding-inline: fonts.rem(32px);
				margin-bottom: fonts.rem(24px);
				gap: fonts.rem(12px);
			}

			@media #{layout.$small-screen-and-smaller} {
				padding-inline: fonts.rem(16px);
			}

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(29px);
					line-height: 0.96;
					letter-spacing: -0.29px;
				}
			}
		}

		.badges-row {
			display: flex;
			align-items: center;
			gap: fonts.rem(16px);
			justify-content: center;
			flex-wrap: wrap;

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(10px);
			}

			.check-badge {
				display: flex;
				align-items: center;
				height: 20px;

				img {
					width: auto;
					height: 24px;
				}

				span {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.4;
					letter-spacing: -0.14px;
					color: colors.$color-gray;
					white-space: nowrap;
				}
			}
		}

		// Disease tag parallax rows
		.tags-area {
			position: relative;
		}

		.disease-list {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(12px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(8px);
			}
		}

		.disease-row-wrapper {
			overflow: hidden;
			width: 100%;
		}

		.disease-row-container {
			overflow: hidden;
		}

		.disease-row-list {
			display: flex;
			white-space: nowrap;
			will-change: transform;
			gap: fonts.rem(12px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(8px);
			}
		}

		.disease-item {
			display: inline-flex;
			align-items: center;
			padding: fonts.rem(11px) fonts.rem(16px);
			background: rgba(255, 255, 255, 0.85);
			backdrop-filter: blur(7.5px);
			-webkit-backdrop-filter: blur(7.5px);
			border-radius: 5px;
			font-family: fonts.$DM-Sans;
			font-weight: 500;
			font-size: fonts.rem(22px);
			line-height: 1.1;
			letter-spacing: -0.44px;
			color: colors.$color-black;
			white-space: nowrap;
			flex-shrink: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(18px);
				letter-spacing: -0.36px;
				padding: fonts.rem(8px) fonts.rem(12px);
			}
		}

		// Desktop: card floats centered over the disease rows (modal style)
		.biomarker-card-float {
			position: absolute;
			top: 50%;
			left: 50%;
			transform: translate(-50%, -50%);
			z-index: 10;
		}

		// Mobile: card sits as a standalone block above the disease rows
		.biomarker-card-standalone {
			display: flex;
			justify-content: center;
			padding: 0 fonts.rem(32px);
			margin-bottom: fonts.rem(24px);

			@media #{layout.$small-screen-and-smaller} {
				padding: 0 fonts.rem(16px);
			}

			.biomarker-card {
				width: 100%;
				max-width: fonts.rem(330px);
				height: fonts.rem(229px);

				.zone-labels .zone-label {
					font-size: fonts.rem(12px);
					letter-spacing: 0.01em;
				}

				.data-marker {
					&.in-range-marker { right: 12%; top: 20%; }
					&.out-of-range-marker { left: 10%; top: 50%; }
				}

				.marker-dot {
					width: fonts.rem(17px);
					height: fonts.rem(17px);
				}
			}
		}

		// The biomarker data card
		.biomarker-card {
			position: relative;
			width: fonts.rem(243px);
			height: fonts.rem(168px);
			background: white;
			border: 1px solid rgba(210, 206, 196, 0.6);
			border-radius: fonts.rem(8.4px);
			overflow: hidden;

			// Left: "In Range" / "Out of Range" labels
			.zone-labels {
				position: absolute;
				left: 0;
				top: 0;
				width: 28%;
				height: 100%;
				display: flex;
				flex-direction: column;

				.zone-label {
					flex: 1;
					display: flex;
					align-items: center;
					justify-content: center;
					font-family: 'Azeret Mono', monospace;
					font-size: fonts.rem(9px);
					line-height: 1.2;
					text-align: center;
					color: rgba(96, 91, 82, 0.8);
					letter-spacing: 0.01em;
				}
			}

			// Thin vertical color bars indicating zone
			.range-bar-col {
				position: absolute;
				left: 28%;
				top: fonts.rem(15px);
				bottom: fonts.rem(15px);
				width: fonts.rem(8px);
				display: flex;
				flex-direction: column;

				.range-bar {
					&.green-zone {
						flex: 0 0 47%;
						background-color: #ccffee;
					}
					&.pink-zone {
						flex: 1;
						background-color: #ffe0e1;
					}
				}
			}

			// Chart area: dashed lines, trend path, data point markers
			.chart-area {
				position: absolute;
				left: calc(28% + #{fonts.rem(8px)});
				top: 0;
				right: 0;
				bottom: 0;

				.chart-line {
					position: absolute;
					left: 0;
					right: 0;
					height: 1px;
					background-image: repeating-linear-gradient(
						to right,
						rgba(96, 91, 82, 0.25) 0,
						rgba(96, 91, 82, 0.25) 4px,
						transparent 4px,
						transparent 8px
					);

					&.top-line    { top: fonts.rem(15px); }
					&.mid-line    { top: 47%; }
					&.bottom-line { bottom: fonts.rem(15px); }
				}

				.trend-svg {
					position: absolute;
					inset: 0;
					width: 100%;
					height: 100%;
					pointer-events: none;
				}

				.data-marker {
					position: absolute;
					display: flex;
					flex-direction: column;
					align-items: center;

					// Out-of-range: lower-left
					&.out-of-range-marker {
						left: 8%;
						top: 52%;
					}

					// In-range: upper-right
					&.in-range-marker {
						right: 10%;
						top: 19%;
					}
				}

				.marker-dot {
					width: fonts.rem(13px);
					height: fonts.rem(13px);
					border-radius: 50%;
					border: 2px solid white;
					box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
					flex-shrink: 0;

					&.green-dot { background-color: #20c475; }
					&.red-dot   { background-color: #fc5358; }
				}

				.marker-stem {
					width: 1px;
					height: fonts.rem(28px);
					background: linear-gradient(to bottom, rgba(210, 206, 196, 0.5), transparent);
					margin-top: 2px;
				}
			}
		}
	}

	/*
	 * =============================
	 * Care Callout
	 * =============================
	 */
	.care-callout {
		background-color: colors.$color-white;

		.container {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(64px);
			padding: fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(48px);
				padding: fonts.rem(48px) fonts.rem(24px);
			}
		}

		// ——— Tout block ———
		.tout-block {
			display: grid;
			grid-template-columns: 1fr 1fr;
			gap: fonts.rem(64px);
			align-items: center;

			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(32px);
			}
		}

		.tout-content {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(24px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(20px);
			}
		}

		.title {
			font-family: fonts.$STIX-Two-Text;
			font-weight: 400;
			font-size: fonts.rem(42px);
			line-height: 1;
			letter-spacing: -0.84px;
			color: colors.$color-black;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(29px);
				letter-spacing: -0.58px;
			}
		}

		.stars-wrapper {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			img {
				width: fonts.rem(90px);
				height: auto;
			}

			span {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				line-height: 1.4;
				color: colors.$color-black;
			}
		}

		.featured-review {
			margin: 0;
			padding: 0;
			display: flex;
			flex-direction: column;
			gap: fonts.rem(12px);

			p {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(18px);
				font-weight: 400;
				line-height: 1.5;
				letter-spacing: -0.18px;
				color: colors.$color-black;
				margin: 0;

				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(16px);
				}
			}

			footer {
				display: flex;
				flex-direction: row;
				align-items: center;
				gap: fonts.rem(8px);

				.name {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 700;
					color: colors.$color-black;
				}

				.label {
					font-family: fonts.$DM-Sans;
					font-size: fonts.rem(14px);
					font-weight: 400;
					color: rgba(96, 91, 82, 0.6);

					&::before {
						content: '·';
						margin-right: fonts.rem(8px);
					}
				}
			}
		}

		.cta-button {
			display: flex;
			align-items: center;
			justify-content: center;
			height: fonts.rem(48px);
			padding: 0 fonts.rem(32px);
			background-color: colors.$color-yellow;
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 500;
			letter-spacing: -0.16px;
			border-radius: 2px;
			text-decoration: none;
			transition: background-color 0.2s ease;
			align-self: flex-start;

			&:hover {
				background-color: colors.$color-yellow-dark;
			}

			@media #{layout.$medium-screen-and-smaller} {
				width: 100%;
				align-self: stretch;
			}
		}

		// ——— Doctor grid ———
		.doctor-grid {
			display: grid;
			grid-template-columns: repeat(2, 1fr);
			gap: fonts.rem(12px);

			@media #{layout.$medium-screen-and-smaller} {
				// 4 tiles in a single row strip on mobile
				grid-template-columns: repeat(4, 1fr);
				gap: fonts.rem(8px);
			}
		}

		.doctor-tile {
			border-radius: fonts.rem(20px);
			overflow: hidden;
			aspect-ratio: 244 / 282;

			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
			}
		}

		// ——— Carousel block ———
		.carousel-block {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(32px);
		}

		.care-callout-carousel {
			overflow-x: hidden;
			overflow-y: visible;
			width: 100%;

			// Slick core inline
			.slick-list {
				overflow: hidden;
				display: block;
				margin: 0;
				padding: 0;

				&.dragging img { pointer-events: none; }
			}

			.slick-track {
				display: flex !important;
				align-items: stretch;
				margin: auto;
			}

			.slick-slide {
				height: inherit;

				> div { height: 100%; }

				// Override global [aria-hidden="true"] { display: none !important }
				// Slick sets aria-hidden on off-screen slides; visual clipping is
				// handled by .slick-list overflow:hidden, not display:none.
				&[aria-hidden="true"] {
					display: block !important;
				}
			}

			.slick-initialized .review-card {
				display: flex !important;
			}
		}

		.review-card {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(16px);
			padding: fonts.rem(24px);
			background-color: #f1f0ef;
			border-radius: fonts.rem(20px);
			margin-inline: fonts.rem(8px);
			height: 100%;

			@media #{layout.$medium-screen-and-smaller} {
				margin-inline: fonts.rem(6px);
			}
		}

		.review-rating img {
			height: fonts.rem(16px);
			width: auto;
		}

		.review-title {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(18px);
			font-weight: 700;
			line-height: 1;
			letter-spacing: -0.36px;
			color: colors.$color-black;
			margin: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(16px);
			}
		}

		.review-text {
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 400;
			line-height: 1.5;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;
			flex: 1;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(14px);
			}
		}

		.review-attribution {
			display: flex;
			flex-direction: row;
			align-items: center;
			gap: fonts.rem(8px);

			.name {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 700;
				color: colors.$color-black;
			}

			.label {
				font-family: fonts.$DM-Sans;
				font-size: fonts.rem(14px);
				font-weight: 400;
				color: rgba(96, 91, 82, 0.6);

				&::before {
					content: '·';
					margin-right: fonts.rem(8px);
				}
			}
		}

		// ——— Navigation ———
		.care-callout-navigation {
			margin-top: 0;
		}

		.care-callout-dots {
			display: flex;
			align-items: center;
			justify-content: center;
			min-width: fonts.rem(84px);

			.slick-dots {
				list-style: none;
				padding: 0;
				margin: 0;
				display: flex !important;
				align-items: center;
				gap: fonts.rem(8px);
				position: static;
				bottom: auto;

				li {
					margin: 0;
					width: auto;
					height: auto;
					line-height: 0;

					button {
						width: 12px;
						height: 12px;
						border-radius: 50%;
						background-color: rgba(96, 91, 82, 0.3);
						border: none;
						padding: 0;
						cursor: pointer;
						font-size: 0;
						line-height: 0;
						transition: background-color 0.3s ease;

						&::before { display: none; }
					}

					&.slick-active button {
						background-color: colors.$color-black;
					}
				}
			}
		}
	}

	/*
	 * =============================
	 * Guide Section
	 * =============================
	 */
	.guide {
		background-color: colors.$color-white;

		.container {
			display: flex;
			flex-direction: column;
			align-items: center;
			gap: fonts.rem(40px);
			padding: fonts.rem(64px);

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(32px);
				padding: fonts.rem(48px) 0;
			}
		}

		.title {
			font-family: fonts.$STIX-Two-Text;
			font-weight: 400;
			font-size: fonts.rem(54px);
			line-height: 1;
			letter-spacing: -1.08px;
			color: colors.$color-black;
			text-align: center;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(36px);
				letter-spacing: -0.72px;
				padding: 0 fonts.rem(24px);
			}
		}

		// ——— Scrollable cards row ———
		.guide-cards {
			display: flex;
			flex-direction: row;
			gap: fonts.rem(24px);
			overflow-x: auto;
			scroll-snap-type: x mandatory;
			-webkit-overflow-scrolling: touch;
			scrollbar-width: none;
			cursor: grab;
			width: 100%;

			&::-webkit-scrollbar { display: none; }
			&:active { cursor: grabbing; }

			@media #{layout.$medium-screen-and-smaller} {
				gap: fonts.rem(16px);
				padding: 0 fonts.rem(24px);
			}
		}

		.guide-card {
			flex: 0 0 fonts.rem(328px);
			scroll-snap-align: start;
			display: flex;
			flex-direction: column;
			gap: fonts.rem(16px);

			@media #{layout.$medium-screen-and-smaller} {
				flex: 0 0 fonts.rem(272px);
			}

			@media #{layout.$small-screen-and-smaller} {
				flex: 0 0 calc(85vw);
			}
		}

		.guide-card-image {
			aspect-ratio: 1 / 1;
			border-radius: fonts.rem(21px);
			overflow: hidden;
			position: relative;

			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
				// If image fails to load, bg-color from inline style shows through
			}
		}

		.guide-card-content {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(8px);
		}

		.card-title {
			font-family: fonts.$DM-Sans;
			font-weight: 500;
			font-size: fonts.rem(22px);
			line-height: 1.1;
			letter-spacing: -0.44px;
			color: colors.$color-black;
			margin: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(18px);
				letter-spacing: -0.36px;
			}
		}

		.card-desc {
			font-family: fonts.$DM-Sans;
			font-weight: 400;
			font-size: fonts.rem(16px);
			line-height: 1.4;
			letter-spacing: -0.16px;
			color: colors.$color-black;
			margin: 0;

			@media #{layout.$medium-screen-and-smaller} {
				font-size: fonts.rem(14px);
				letter-spacing: -0.14px;
			}
		}

		// ——— CTA ———
		.cta-button {
			display: flex;
			align-items: center;
			justify-content: center;
			height: fonts.rem(48px);
			width: fonts.rem(366px);
			background-color: colors.$color-yellow;
			color: colors.$color-black;
			font-family: fonts.$DM-Sans;
			font-size: fonts.rem(16px);
			font-weight: 500;
			letter-spacing: -0.32px;
			border-radius: 2px;
			border: 1px solid rgba(14, 11, 32, 0.2);
			text-decoration: none;
			transition: background-color 0.2s ease;

			&:hover {
				background-color: colors.$color-yellow-dark;
			}

			@media #{layout.$medium-screen-and-smaller} {
				width: calc(100% - fonts.rem(48px));
			}
		}

		.care-callout-dots {
			display: flex;
			align-items: center;
			justify-content: center;
			min-width: fonts.rem(84px);

			.slick-dots {
				list-style: none;
				padding: 0;
				margin: 0;
				display: flex !important;
				align-items: center;
				gap: fonts.rem(8px);
				position: static;
				bottom: auto;

				li {
					margin: 0;
					width: auto;
					height: auto;
					line-height: 0;

					button {
						width: 12px;
						height: 12px;
						border-radius: 50%;
						background-color: rgba(96, 91, 82, 0.3);
						border: none;
						padding: 0;
						cursor: pointer;
						font-size: 0;
						line-height: 0;
						transition: background-color 0.3s ease;

						&::before { display: none; }
					}

					&.slick-active button {
						background-color: colors.$color-black;
					}
				}
			}
		}
	}
}

@keyframes marquee-scroll {
	from {
		transform: translateX(0);
	}
	to {
		transform: translateX(var(--marquee-offset, -50%));
	}
}

