    @media #{layout.$small-screen-and-smaller} {
        padding: 24px 15px;
    }

    .progress-bar {
        display: flex;
        width: 100%;
        max-width: 632px;

        .progress-segment {
            flex: 1;
            height: 4px;
            background-color: colors.$color-white;
            transition: background-color 0.3s ease;

            &.active {
                background-color: colors.$color-green-dark;
            }
        }
    }

    .quiz-content {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 24px;
        width: 632px;
        max-width: 100%;
    }

    #question {
        font-family: fonts.$STIX-Two-Text;
        font-weight: 400;
        font-size: 40px;
        line-height: 48px;
        text-align: center;
