        @media #{layout.$medium-screen-and-smaller} {
            font-size: 36px;
            line-height: 40px;
        }

        @media #{layout.$small-screen-and-smaller} {
            font-size: 28px;
            line-height: 32px;
        }
    }

    .options-container {
        display: grid;
        grid-template-columns: repeat(2, 312px);
        gap: 18px;
        justify-content: center;

        @media #{layout.$medium-screen-and-smaller} {
            grid-template-columns: repeat(2, 1fr);
        }

        @media #{layout.$small-screen-and-smaller} {
            grid-template-columns: 1fr;
        }
    }

    .option-button {
        height: 64px;
        padding: 12px 32px;
        border-radius: 2px;
        border: none;
        background-color: colors.$color-white;
        color: colors.$color-black;
        font-family: fonts.$DM-Sans;
        font-weight: 500;
        font-size: 16px;
        line-height: 24px;
